 26→/**
 27→ * 考生端-考试记录服务
 28→ */
 29→@Slf4j
 30→@Service
 31→public class ExamRecordService {
 32→
 33→    private final ExamMapper examMapper;
 34→    private final ExamRecordMapper examRecordMapper;
 35→    private final ExamRecordQuestionMapper examRecordQuestionMapper;
 36→    private final AnswerDetailMapper answerDetailMapper;
 37→    private final QuestionBankMapper questionBankMapper;
 38→    private final ExamWhitelistMapper examWhitelistMapper;
 39→
 40→    public ExamRecordService(ExamMapper examMapper,
 41→                             ExamRecordMapper examRecordMapper,
 42→                             ExamRecordQuestionMapper examRecordQuestionMapper,
 43→                             AnswerDetailMapper answerDetailMapper,
 44→                             QuestionBankMapper questionBankMapper,
 45→                             ExamWhitelistMapper examWhitelistMapper) {
 46→        this.examMapper = examMapper;
 47→        this.examRecordMapper = examRecordMapper;
 48→        this.examRecordQuestionMapper = examRecordQuestionMapper;
 49→        this.answerDetailMapper = answerDetailMapper;
 50→        this.questionBankMapper = questionBankMapper;
 51→        this.examWhitelistMapper = examWhitelistMapper;
 52→    }
 53→
 54→    /**
 55→     * 考生端-分页查询可参加的考试列表
 56→     */
 57→    public IPage<ExamDetailResponse> listExams(Long userId, int page, int size) {
 58→        // 查询所有已发布考试（数量通常不大）
 59→        List<Exam> publishedExams = examMapper.selectList(
 60→                new LambdaQueryWrapper<Exam>().eq(Exam::getStatus, ExamStatus.PUBLISHED));
 61→
 62→        // 按访问权限过滤
 63→        List<ExamDetailResponse> filtered = publishedExams.stream()
 64→                .filter(exam -> hasAccess(exam, userId))
 65→                .map(exam -> buildExamDetailResponse(exam, userId))
 66→                .collect(Collectors.toList());
 67→
 68→        // 手动分页
 69→        int total = filtered.size();
 70→        int fromIndex = Math.min((page - 1) * size, total);
 71→        int toIndex = Math.min(fromIndex + size, total);
 72→        List<ExamDetailResponse> pageRecords = filtered.subList(fromIndex, toIndex);
 73→
 74→        Page<ExamDetailResponse> result = new Page<>(page, size, total);
 75→        result.setRecords(pageRecords);
 76→        return result;
 77→    }
 78→
 79→    /**
 80→     * 考生端-查询考试详情
 81→     */
 82→    public ExamDetailResponse getExamDetail(Long examId, Long userId) {
 83→        Exam exam = getPublishedExamOrThrow(examId);
 84→        checkAccess(exam, userId);
 85→        return buildExamDetailResponse(exam, userId);
 86→    }
 87→
 88→    /**
 89→     * 开始考试：校验 → 抽题 → 创建记录
 90→     */
 91→    @Transactional(rollbackFor = Exception.class)
 92→    public ExamStartResponse startExam(Long examId, Long userId) {
 93→        // 1. 校验考试状态
 94→        Exam exam = getPublishedExamOrThrow(examId);
 95→
 96→        // 2. 校验访问权限
 97→        checkAccess(exam, userId);
 98→
 99→        // 3. 校验最大考试次数
100→        long completedCount = countCompletedRecords(examId, userId);
101→        if (exam.getMaxAttempts() > 0 && completedCount >= exam.getMaxAttempts()) {
102→            throw new BizException(ErrorCode.MAX_ATTEMPTS_REACHED);
103→        }
104→
105→        // 4. 校验是否存在进行中的考试
106→        long inProgressCount = examRecordMapper.selectCount(
107→                new LambdaQueryWrapper<ExamRecord>()
108→                        .eq(ExamRecord::getExamId, examId)
109→                        .eq(ExamRecord::getUserId, userId)
110→                        .eq(ExamRecord::getStatus, RecordStatus.IN_PROGRESS));
111→        if (inProgressCount > 0) {
112→            throw new BizException(ErrorCode.EXAM_IN_PROGRESS);
113→        }
114→
115→        // 5. 抽题
116→        List<QuestionBank> allQuestions = questionBankMapper.selectList(
117→                new LambdaQueryWrapper<QuestionBank>()
118→                        .eq(QuestionBank::getExamId, examId)
119→                        .orderByAsc(QuestionBank::getSortOrder));
120→
121→        List<QuestionBank> drawnQuestions = drawQuestions(allQuestions, exam.getQuestionCount());
122→
123→        // 6. 创建考试记录
124→        ExamRecord record = ExamRecord.builder()
125→                .examId(examId)
126→                .userId(userId)
127→                .startTime(LocalDateTime.now())
128→                .status(RecordStatus.IN_PROGRESS)
129→                .attemptNo((int) completedCount + 1)
130→                .build();
131→        examRecordMapper.insert(record);
132→
133→        // 7. 插入记录-题目关联
134→        for (int i = 0; i < drawnQuestions.size(); i++) {
135→            ExamRecordQuestion erq = ExamRecordQuestion.builder()
136→                    .recordId(record.getId())
137→                    .questionId(drawnQuestions.get(i).getId())
138→                    .sortOrder(i + 1)
139→                    .build();
140→            examRecordQuestionMapper.insert(erq);
141→        }
142→
143→        // 8. 构建响应（不含正确答案和解析）
144→        ExamStartResponse response = new ExamStartResponse();
145→        response.setRecordId(record.getId());
146→        List<ExamStartResponse.QuestionVO> questionVOs = new ArrayList<>(drawnQuestions.size());
147→        for (int i = 0; i < drawnQuestions.size(); i++) {
148→            QuestionBank q = drawnQuestions.get(i);
149→            ExamStartResponse.QuestionVO vo = new ExamStartResponse.QuestionVO();
150→            vo.setId(q.getId());
151→            vo.setContent(q.getContent());
152→            vo.setOptionA(q.getOptionA());
153→            vo.setOptionB(q.getOptionB());
154→            vo.setOptionC(q.getOptionC());
155→            vo.setOptionD(q.getOptionD());
156→            vo.setSortOrder(i + 1);
157→            questionVOs.add(vo);
158→        }
159→        response.setQuestions(questionVOs);
160→
161→        log.info("[lbl][Exam][START] 开始考试, userId={}, examId={}, recordId={}, questionCount={}",
162→                userId, examId, record.getId(), drawnQuestions.size());
163→
164→        return response;
165→    }
166→
167→    /**
168→     * 恢复进行中的考试：校验记录状态 → 返回题目列表
169→     */
170→    public ExamStartResponse resumeExam(Long examId, Long recordId, Long userId) {
171→        ExamRecord record = examRecordMapper.selectById(recordId);
172→        if (record == null) {
173→            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
174→        }
175→        if (!record.getUserId().equals(userId) || !record.getExamId().equals(examId)) {
176→            throw new BizException(ErrorCode.FORBIDDEN);
177→        }
178→        if (record.getStatus() != RecordStatus.IN_PROGRESS) {
179→            throw new BizException(ErrorCode.RECORD_ALREADY_SUBMITTED);
180→        }
181→
182→        // 查询本次考试抽中的题目
183→        List<ExamRecordQuestion> recordQuestions = examRecordQuestionMapper.selectList(
184→                new LambdaQueryWrapper<ExamRecordQuestion>()
185→                        .eq(ExamRecordQuestion::getRecordId, recordId)
186→                        .orderByAsc(ExamRecordQuestion::getSortOrder));
187→        List<Long> questionIds = recordQuestions.stream()
188→                .map(ExamRecordQuestion::getQuestionId)
189→                .collect(Collectors.toList());
190→        Map<Long, QuestionBank> questionMap = questionBankMapper.selectBatchIds(questionIds)
191→                .stream()
192→                .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));
193→
194→        // 构建响应（不含正确答案和解析）
195→        ExamStartResponse response = new ExamStartResponse();
196→        response.setRecordId(recordId);
197→        List<ExamStartResponse.QuestionVO> questionVOs = new ArrayList<>(recordQuestions.size());
198→        for (ExamRecordQuestion rq : recordQuestions) {
199→            QuestionBank q = questionMap.get(rq.getQuestionId());
200→            if (q == null) continue;
201→            ExamStartResponse.QuestionVO vo = new ExamStartResponse.QuestionVO();
202→            vo.setId(q.getId());
203→            vo.setContent(q.getContent());
204→            vo.setOptionA(q.getOptionA());
205→            vo.setOptionB(q.getOptionB());
206→            vo.setOptionC(q.getOptionC());
207→            vo.setOptionD(q.getOptionD());
208→            vo.setSortOrder(rq.getSortOrder());
209→            questionVOs.add(vo);
210→        }
211→        response.setQuestions(questionVOs);
212→
213→        log.info("[lbl][Exam][RESUME] 恢复考试, userId={}, examId={}, recordId={}, questionCount={}",
214→                userId, examId, recordId, questionVOs.size());
215→
216→        return response;
217→    }
218→
219→    /**
220→     * 提交考试：评分 → 保存答题明细 → 更新记录
221→     */
222→    @Transactional(rollbackFor = Exception.class)
223→    public ExamSubmitResponse submitExam(ExamSubmitRequest req, Long userId) {
224→        // 1. 校验记录
225→        ExamRecord record = examRecordMapper.selectById(req.getRecordId());
226→        if (record == null) {
227→            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
228→        }
229→        if (!record.getUserId().equals(userId)) {
230→            throw new BizException(ErrorCode.FORBIDDEN);
231→        }
232→        if (record.getStatus() != RecordStatus.IN_PROGRESS) {
233→            throw new BizException(ErrorCode.RECORD_ALREADY_SUBMITTED);
234→        }
235→
236→        // 2. 判断是否超时
237→        Exam exam = examMapper.selectById(record.getExamId());
238→        RecordStatus status;
239→        if (exam.getTimeLimitMin() != null && exam.getTimeLimitMin() > 0
240→                && Duration.between(record.getStartTime(), LocalDateTime.now()).toMinutes() > exam.getTimeLimitMin()) {
241→            status = RecordStatus.TIMEOUT;
242→        } else {
243→            status = RecordStatus.SUBMITTED;
244→        }
245→
246→        // 3. 获取本次考试抽中的题目
247→        List<ExamRecordQuestion> recordQuestions = examRecordQuestionMapper.selectList(
248→                new LambdaQueryWrapper<ExamRecordQuestion>()
249→                        .eq(ExamRecordQuestion::getRecordId, req.getRecordId()));
250→        List<Long> drawnQuestionIds = recordQuestions.stream()
251→                .map(ExamRecordQuestion::getQuestionId)
252→                .collect(Collectors.toList());
253→
254→        // 4. 查询题目详情
255→        Map<Long, QuestionBank> questionMap = questionBankMapper.selectBatchIds(drawnQuestionIds)
256→                .stream()
257→                .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));
258→
259→        // 5. 评分
260→        int totalQuestions = drawnQuestionIds.size();
261→        BigDecimal pointsPerQuestion = new BigDecimal(100)
262→                .divide(new BigDecimal(totalQuestions), 2, RoundingMode.HALF_UP);
263→        int correctCount = 0;
264→
265→        for (AnswerItem item : req.getAnswers()) {
266→            QuestionBank question = questionMap.get(item.getQuestionId());
267→            boolean isCorrect = question != null && item.getAnswer().equals(question.getCorrectAnswer());
268→            if (isCorrect) {
269→                correctCount++;
270→            }
271→
272→            // 保存答题明细
273→            AnswerDetail detail = AnswerDetail.builder()
274→                    .recordId(req.getRecordId())
275→                    .questionId(item.getQuestionId())
276→                    .userAnswer(item.getAnswer())
277→                    .isCorrect(isCorrect)
278→                    .build();
279→            answerDetailMapper.insert(detail);
280→        }
281→
282→        BigDecimal score = pointsPerQuestion.multiply(new BigDecimal(correctCount));
283→
284→        // 6. 更新考试记录
285→        record.setScore(score);
286→        record.setEndTime(LocalDateTime.now());
287→        record.setStatus(status);
288→        examRecordMapper.updateById(record);
289→
290→        log.info("[lbl][Exam][SUBMIT] 提交考试, userId={}, recordId={}, score={}, status={}",
291→                userId, req.getRecordId(), score, status.getValue());
292→
293→        // 7. 构建响应
294→        ExamSubmitResponse response = new ExamSubmitResponse();
295→        response.setScore(score);
296→        response.setStatus(status.getValue());
297→        return response;
298→    }
299→
300→    /**
301→     * 考生端-分页查询考试记录列表
302→     */
303→    public IPage<RecordDetailResponse> listRecords(Long userId, int page, int size) {
