474→    /**
475→     * 统计用户在某考试下已完成的记录数（submitted + timeout）
476→     */
477→    private long countCompletedRecords(Long examId, Long userId) {
478→        return examRecordMapper.selectCount(
479→                new LambdaQueryWrapper<ExamRecord>()
480→                        .eq(ExamRecord::getExamId, examId)
481→                        .eq(ExamRecord::getUserId, userId)
482→                        .in(ExamRecord::getStatus, RecordStatus.SUBMITTED, RecordStatus.TIMEOUT));
483→    }
