485→    /**
486→     * 抽题逻辑：随机抽取指定数量的题目
487→     */
488→    private List<QuestionBank> drawQuestions(List<QuestionBank> allQuestions, Integer questionCount) {
489→        List<QuestionBank> pool = new ArrayList<>(allQuestions);
490→        if (questionCount == null || questionCount == 0 || questionCount >= pool.size()) {
491→            // 使用全部题目，打乱顺序
492→            Collections.shuffle(pool);
493→            return pool;
494→        }
495→        // 随机抽取指定数量
496→        Collections.shuffle(pool);
497→        List<QuestionBank> selected = new ArrayList<>(pool.subList(0, questionCount));
498→        // 再次打乱保证随机顺序
499→        Collections.shuffle(selected);
500→        return selected;
501→    }
