503→    /**
504→     * 构建考试详情响应
505→     */
506→    private ExamDetailResponse buildExamDetailResponse(Exam exam, Long userId) {
507→        ExamDetailResponse resp = new ExamDetailResponse();
508→        resp.setId(exam.getId());
509→        resp.setTitle(exam.getTitle());
510→        resp.setStatus(exam.getStatus().getValue());
511→        resp.setTimeLimitMin(exam.getTimeLimitMin());
512→        resp.setMaxAttempts(exam.getMaxAttempts());
513→        resp.setShowAnswer(exam.getShowAnswer());
514→        resp.setShowAnalysis(exam.getShowAnalysis());
515→        resp.setAccessMode(exam.getAccessMode().getValue());
516→
517→        // 查询题库实际题目数
518→        long actualCount = questionBankMapper.selectCount(
519→                new LambdaQueryWrapper<QuestionBank>()
520→                        .eq(QuestionBank::getExamId, exam.getId()));
521→        resp.setTotalQuestionCount((int) actualCount);
522→        // questionCount 为抽题数量，0 表示全部
523→        int displayCount = (exam.getQuestionCount() == null || exam.getQuestionCount() == 0)
524→                ? (int) actualCount
525→                : Math.min(exam.getQuestionCount(), (int) actualCount);
526→        resp.setQuestionCount(displayCount);
527→
528→        // 计算剩余次数
529→        if (exam.getMaxAttempts() == null || exam.getMaxAttempts() == 0) {
530→            resp.setRemainingAttempts(null);
531→        } else {
532→            long completed = countCompletedRecords(exam.getId(), userId);
533→            resp.setRemainingAttempts(Math.max(0, exam.getMaxAttempts() - (int) completed));
534→        }
535→
536→        // 查询是否有进行中的考试记录
537→        ExamRecord inProgressRecord = examRecordMapper.selectOne(
538→                new LambdaQueryWrapper<ExamRecord>()
539→                        .eq(ExamRecord::getExamId, exam.getId())
540→                        .eq(ExamRecord::getUserId, userId)
541→                        .eq(ExamRecord::getStatus, RecordStatus.IN_PROGRESS)
542→                        .last("LIMIT 1"));
543→        if (inProgressRecord != null) {
544→            resp.setInProgressRecordId(inProgressRecord.getId());
545→        }
546→
547→        resp.setCreatedAt(exam.getCreatedAt());
548→
549→        return resp;
550→    }
